  ('social-worker-moex-06020', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Ann Hartman所發展的瞭解案主與周遭體系（親人、朋友、工作、健康照顧、教會等……）之關係，瞭解 案主與各體系間之關係強弱，正負壓力，作為評估的工具，此種圖稱為下列何者？', '["家庭生態圖", "家系圖", "家庭功能圖", "家庭結構圖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06021', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關「人在情境（PIE）」，社會工作者評估案主社會功能時，評估層面不包括：', '["社會角色問題", "靈性問題", "環境問題", "心理違常問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06022', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「預立醫療指示」安排是由：', '["患者生前自己作決定", "患者昏迷時由家屬作決定", "由醫療團隊作決定", "重要關係人作決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06023', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「空殼婚姻」的敘述，何者錯誤？', '["「空殼婚姻」係指配偶之間並沒有強烈的情感，外在壓力迫使雙方繼續維持婚姻", "「空殼婚姻」無Sternberg所提出之「愛情三角理論」中的激情、親密與承諾三成分", "夫妻可能因為工作上的理由、外人的觀感、投資的理由、道德的考量等外在壓力，決定維繫空殼婚姻", "Cuber和Harroff（1971）將空殼婚姻分為無活力關係、習慣衝突關係、被動協調關係等三大類別"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06024', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者並非是「生命週期觀點」的主要概念？', '["著重在個案的生命路徑如何受到歷史背景、情境和偶發事件的形塑", "生命週期觀點著重在描述和解釋與年齡相關的生理、心理與社會的改變", "該觀點認為改變在人的一生中不斷的發生，意味著人格具有可塑性或改變的能力", "該觀點推翻了漏斗理論的假設，認為個體不是對環境刺激進行一種定型或機械式的被動回應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06025', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關中年人在家庭面向的敘述，何者錯誤？', '["中年女性需同時照顧上一代的父母與下一代的子女，被形容為「三明治世代」", "中年人大多扮演大家族中，「親屬關係維繫者」的角色，確保家族成員的彼此互動、情緒及實際需求 等獲得滿足", "「回力鏢世代」（boomerang generation）對中年人家庭生活，產生負向的干擾", "中年人眼看雙親逐漸老邁，將使他們更加留意自身的老化過程，也會更重視自己的健康維護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06026', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「生命結構」（life structure）是那一位學者的理論核心？', '["艾瑞克生（Erikson）", "亞聶（Arnett）", "魏蘭（Vaillant）", "李文生（Levinson）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06027', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「人類的所有自我犧牲或是利他行為，都是為了延續生存」，這是下列那一個理論的主要論點？', '["社會心理學", "社會神經科學", "社會生物學", "人體神經科學"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06028', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '6～18歲的兒童與青少年，會逐漸開始發展「對自己社會思想的覺察、思考與評價能力」，這種能力稱為：', '["社會意向解讀（intention-cue detection）", "社會認知監控（social cognitive monitoring）", "角色採取能力（role-taking ability）", "角色區辨能力（role-distinguishing ability）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06029', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「社會認同理論」的敘述，何者錯誤？', '["團體中的人們透過對於其他成員角色的理解與模仿，而產生人際互動學習機制", "社會認同讓團體成員產生或維持可以迎合團體的價值與理念的態度與行為", "人際互動所產生的認同感對於個體或成員的想法與行為會產生影響，這與人格特質對個體的影響有所不同", "由於認同自己的團體，常會高估所屬團體的功能及價值"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
